61	package mem is
62		type T_MEM_FILEFORMAT is (
63			MEM_FILEFORMAT_INTEL_HEX,
64			MEM_FILEFORMAT_LATTICE_MEM,
65			MEM_FILEFORMAT_XILINX_MEM
66		);
67	
68		type T_MEM_CONTENT is (
69			MEM_CONTENT_BINARY,
70			MEM_CONTENT_DECIMAL,
71			MEM_CONTENT_HEX
72		);
73	
74		function mem_FileExtension(Filename : string) return string;
75	
76		impure function mem_ReadMemoryFile(
77			FileName : string;
78			MemoryLines : positive;
79			BitsPerMemoryLine : positive;
80			FORMAT : T_MEM_FILEFORMAT;
81			CONTENT : T_MEM_CONTENT := MEM_CONTENT_HEX
82		) return T_SLM;
83	end package;
84	
