86	package body mem is
87		function mem_FileExtension(FileName : string) return string is
88		begin
89			for i in FileName'high downto FileName'low loop
90				if (FileName(i) = '.') then
91					return str_toLower(FileName(i + 1 to FileName'high));
92				end if;
93			end loop;
94			return "";
95		end function;
96	
97		procedure ReadHex(L : inout LINE; Value : out std_logic_vector; Good : out boolean) is
98			variable ok					: boolean;
99			variable Char				: character;
100			variable Digit			: T_DIGIT_HEX;
101			constant DigitCount	: positive			:= div_ceil(Value'length, 4);
102			variable slv				: std_logic_vector((DigitCount * 4) - 1 downto 0);
103			variable Swapped		: std_logic_vector((DigitCount * 4) - 1 downto 0);
104		begin
105			Good		:= TRUE;
106			for i in 0 to DigitCount - 1 loop
107				read(L, Char, ok);
108				if not ok then
109					Swapped	:= swap(slv, 4);
110					Value		:= Swapped(Value'length - 1 downto 0);
111					return;
112				end if;
113				Digit := to_digit_hex(Char);
114				if Digit = -1 then
115					Good := FALSE;
116					return;
117				end if;
118				slv(i * 4 + 3 downto i * 4)	:= to_slv(Digit, 4);
119			end loop;
120			Swapped	:= swap(slv, 4);
121			Value		:= Swapped(Value'length - 1 downto 0);
122		end procedure;
123	
124		-- Reads a memory file and returns a 2D std_logic matrix
125		impure function mem_ReadMemoryFile(
126			FileName : string;
127			MemoryLines : positive;
128			BitsPerMemoryLine : positive;
129			FORMAT : T_MEM_FILEFORMAT;
130			CONTENT : T_MEM_CONTENT := MEM_CONTENT_HEX
131		) return T_SLM is
132			file FileHandle				: TEXT open READ_MODE is FileName;
133			variable CurrentLine	: LINE;
134			variable Good					: boolean;
135			variable TempWord			: std_logic_vector((div_ceil(BitsPerMemoryLine, 4) * 4) - 1 downto 0);
136			variable Result				: T_SLM(MemoryLines - 1 downto 0, BitsPerMemoryLine - 1 downto 0);
137		begin
138			Result := (others => (others => ite(SIMULATION, 'U', '0')));
139	
140			if FORMAT = MEM_FILEFORMAT_XILINX_MEM then
141				-- discard the first line of a mem file
142				readline(FileHandle, CurrentLine);
143			end if;
144	
145			for i in 0 to MemoryLines - 1 loop
146				exit when endfile(FileHandle);
147	
148				readline(FileHandle, CurrentLine);
149	--			report CurrentLine.all severity NOTE;
150				ReadHex(CurrentLine, TempWord, Good);
151				if not Good then
152					report "Error while reading memory file '" & FileName & "'." severity FAILURE;
153					return Result;
154				end if;
155				for j in 0 to BitsPerMemoryLine - 1 loop
156					Result(i, j) := TempWord(j);
157				end loop;
158			end loop;
159			return  Result;
160		end function;
161	end package body;
